export function useCategoryTransactionDetail(currency: Currency) {
  const { openDialog } = useDialogStack();

  const handleTransactionClick = useCallback(
    (transaction: CategoryTransaction) => {
      openDialog({
        hideXClose: true,
        maxWidth: 400,
        children: (modal) => (
          <AppDialogContent sx={{ m: 0, p: 0 }}>
            <CategoryTransactionDetailContent
              currency={currency}
